import React, { useEffect, useMemo, useState } from "react";
import axios from "axios";
import FAWInput from "../../../../../component-widget/FAWInput";
import FAWButton from "../../../../../component-widget/FAWButton";
import FAWDropdown from "../../../../../component-widget/FAWDropdown";
import FAWCheckbox from "../../../../../component-widget/FAWCheckbox";
import { Tooltip } from "@mui/material";

// Restricted RefCode domains that cannot be changed once set on an existing question
const RESTRICTED_DOMAINS = ["CompanyLegalForm", "IndustryType", "RelationshipType"];

/**
 * Checks if a RefCode domain is restricted (cannot be changed once set)
 * @param {string} domainName - The domain name to check
 * @returns {boolean} True if the domain is restricted
 */
const isRestrictedRefCodeDomain = (domainName) => {
  if (!domainName) return false;
  return RESTRICTED_DOMAINS.some(d => d.toLowerCase() === domainName.toLowerCase());
};

export default function FAWItemOptionsEditor({
  options: initialOptions = [],
  optionsRefDomain: initialDomain = "",
  allowConflictFlag = false,
  conflictValues: initialConflicts = [],
  // New props to mirror legacy flows
  allowedModes = ["RefCode", "StaticList", "Dependency", "FormField"],
  defaultMode = null, // Allow override of default mode
  availableDroplists = [], // [{ label, value }]
  availableFormFields = [], // [{ label, value }]
  availableRefDomains = [], // [{ label, value }] for RefCode dropdown
  domains = [], // Raw domains data for proper formatting
  isCustomField = false, // Whether this is a custom field (from CustomFields domain)
  dependency: initialDependency = null, // { parentDroplist, dependencyDomain } for Dependency mode
  onChange,
  isExistingQuestion = false, // Whether this is an existing question being edited
  isDeployed = false, // Whether the form version is deployed
}) {
  // Remove hardcoded filtering - the API already filters domains appropriately
  // The API uses BaseQuestionItemEditor.SelectDomains constants and filters by:
  // 1. Predefined whitelist of allowed domains
  // 2. User permissions (canAddGenQuestItems)
  // 3. Questionnaire category (adds CustomFields for Internal category)
  // So we should use ALL domains returned by the API without additional filtering
  const getInternalMode = (legacyMode) => {
    switch (legacyMode) {
      case "RefCode": return "refCode";
      case "StaticList": return "staticList";
      case "Dependency": return "dependency";
      case "FormField": return "formField";
      default: return "staticList";
    }
  };
  
  const getLegacyMode = (internalMode) => {
    switch (internalMode) {
      case "refCode": return "RefCode";
      case "staticList": return "StaticList";
      case "dependency": return "Dependency";
      case "formField": return "FormField";
      default: return "StaticList";
    }
  };

  const calculatedDefaultMode = defaultMode 
    ? getInternalMode(defaultMode)
    : initialDomain
    ? "refCode"
    : (allowedModes.includes("StaticList") ? "staticList" : (allowedModes.includes("RefCode") ? "refCode" : getInternalMode(allowedModes[0])));
  const [mode, setMode] = useState(calculatedDefaultMode);
  const [prevMode, setPrevMode] = useState(calculatedDefaultMode);
  const [domain, setDomain] = useState(initialDomain || "");

  // Track if the initial domain is a restricted domain (for existing questions)
  const [originalRestrictedDomain] = useState(() => {
    if (isExistingQuestion && initialDomain && isRestrictedRefCodeDomain(initialDomain)) {
      return initialDomain;
    }
    return null;
  });

  // Determine if the refDomain dropdown should be disabled
  const isRefDomainRestricted = useMemo(() => {
    // If this is an existing question with a restricted domain, lock the dropdown
    if (isExistingQuestion && originalRestrictedDomain) {
      return true;
    }
    // Also check if the currently selected domain is restricted (for existing questions)
    if (isExistingQuestion && initialDomain && isRestrictedRefCodeDomain(initialDomain)) {
      return true;
    }
    return false;
  }, [isExistingQuestion, originalRestrictedDomain, initialDomain]);

  const [inlineOptions, setInlineOptions] = useState(() => {
    if (initialOptions && initialOptions.length > 0) {
      return initialOptions.map((o, i) => ({ 
        id: Date.now() + i, 
        optionText: o.optionText || o.OptionText || "", 
        optionValue: o.optionValue || o.OptionValue || "", 
        conflict: !!o.conflict 
      }));
    } else {
      // Default to 5 empty rows like legacy system
      return Array.from({ length: 5 }, (_, i) => ({
        id: Date.now() + i,
        optionText: "",
        optionValue: "",
        conflict: false
      }));
    }
  });
  const [conflicts, setConflicts] = useState(new Set(initialConflicts));
  const [domainOptions, setDomainOptions] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [dependencyDroplist, setDependencyDroplist] = useState(initialDependency?.parentDroplist || "");
  const [dependencyDomain, setDependencyDomain] = useState(initialDependency?.dependencyDomain || "");
  const [formFieldId, setFormFieldId] = useState("");
   const [useRefCodes, setUseRefCodes] = useState(!!initialDomain || allowedModes.includes("RefCode"));
   const [selectedRefDomain, setSelectedRefDomain] = useState(initialDomain || "");
   const SAVE_VALUE_REGEX = /^[a-zA-Z0-9]*$/;

  useEffect(() => {
    notify();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [mode, domain, inlineOptions, conflicts, useRefCodes, selectedRefDomain, dependencyDroplist, dependencyDomain, formFieldId]);

  const notify = () => {
    if (typeof onChange === "function") {
      const payload = {
        optionsRefDomain: mode === "refCode" && selectedRefDomain ? selectedRefDomain : "",
        options: mode === "staticList" ? inlineOptions.map(({ optionText, optionValue, conflict }) => ({ optionText, optionValue, conflict })) : [],
        conflictValues: Array.from(conflicts.values()),
        mode: getLegacyMode(mode),
      };
      if (mode === "dependency") {
        payload.dependency = {
          parentDroplist: dependencyDroplist || "",
          dependencyDomain: dependencyDomain || "",
        };
      }
      if (mode === "formField") {
        payload.formField = {
          formFieldId: formFieldId || "",
        };
      }
      if (mode === "refCode") {
        payload.refCode = {
          useRefCodes: useRefCodes,
          selectedRefDomain: selectedRefDomain || "",
        };
      }
      onChange(payload);
    }
  };

  const addRow = () => {
    setInlineOptions(prev => [...prev, { id: Date.now() + Math.random(), optionText: "", optionValue: "", conflict: false }]);
  };
  const updateRow = (id, patch) => {
    setInlineOptions(prev => prev.map(r => (r.id === id ? { ...r, ...patch } : r)));
  };
  const removeRow = (id) => {
    setInlineOptions(prev => prev.filter(r => r.id !== id));
  };
  const moveRow = (id, dir) => {
    setInlineOptions(prev => {
      const idx = prev.findIndex(r => r.id === id);
      if (idx < 0) return prev;
      const next = [...prev];
      const swapIdx = dir === "up" ? idx - 1 : idx + 1;
      if (swapIdx < 0 || swapIdx >= next.length) return prev;
      const t = next[idx]; next[idx] = next[swapIdx]; next[swapIdx] = t;
      return next;
    });
  };

  const fetchDomainOptions = async (domainName) => {
    if (!domainName) return;
    setLoading(true); setError("");
    try {
      const response = await axios.get('/RefCode/GetRefCodesOfDomain', { 
        params: { domainCode: domainName } 
      });
      const list = Array.isArray(response.data) ? response.data : [];
      const mapped = list.map(rc => ({ optionValue: rc.Code, optionText: rc.Meaning }));
      setDomainOptions(mapped);
    } catch (e) {
      setError(`Unable to load ref domain options: ${e.message}`);
      setDomainOptions([]);
    } finally {
      setLoading(false);
    }
  };

     useEffect(() => {
     if (mode === "refCode" && selectedRefDomain && selectedRefDomain.trim() !== "") {
       fetchDomainOptions(selectedRefDomain);
     } else if (mode === "refCode" && (!selectedRefDomain || selectedRefDomain.trim() === "")) {
       // Clear domain options when no domain is selected
       setDomainOptions([]);
       setError("");
     }
   }, [mode, selectedRefDomain]);

  // Clear inline options when switching from other modes to staticList
  useEffect(() => {
    // Only reset if switching TO staticList mode, not if already in staticList
    if (mode === "staticList" && prevMode !== "staticList") {
      // Reset to 5 empty rows when switching to staticList mode
      setInlineOptions(Array.from({ length: 5 }, (_, i) => ({
        id: Date.now() + i,
        optionText: "",
        optionValue: "",
        conflict: false
      })));
    }
    setPrevMode(mode);
  }, [mode, prevMode]);

  

  const sourceOptions = [
    allowedModes.includes("RefCode") && { label: "Get values from RefCodes", value: "refCode" },
    allowedModes.includes("StaticList") && { label: "Specify explicit values here", value: "staticList" },
    allowedModes.includes("Dependency") && { label: "Dependent list of values", value: "dependency" },
    // allowedModes.includes("FormField") && { label: "Get values from other Fields", value: "formField" },
  ].filter(Boolean);

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
      <div style={{ display: "flex", gap: 16, flexWrap: "wrap" }}>
        <FAWDropdown
          label="Select the Droplist Source:"
          value={mode}
          onChange={(opt)=> setMode(opt.value)}
          options={sourceOptions}
          disabled={isCustomField}
        />
        
        {mode === "refCode" && (
          <>
            <Tooltip 
              title={isRefDomainRestricted 
                ? `This refcode domain (${selectedRefDomain || initialDomain}) cannot be changed because it is restricted. Restricted domains: ${RESTRICTED_DOMAINS.join(", ")}.`
                : ""
              }
              placement="top"
            >
              <div style={{ display: 'inline-block' }}>
                <FAWDropdown
                  label="Refcode Domains:"
                  value={selectedRefDomain}
                  onChange={(opt) => {
                    // Prevent changes if domain is restricted
                    if (isRefDomainRestricted) {
                      console.warn("Cannot change restricted RefCode domain:", selectedRefDomain || initialDomain);
                      return;
                    }
                    setSelectedRefDomain(opt?.value || "");
                  }}
                  options={[
                    { label: "--Select--", value: "" },
                    ...(domains || [])
                      .map(d => ({
                        label: d.Name || d.Description || String(d),
                        value: d.Name || String(d)
                      }))
                  ]}
                  disabled={isRefDomainRestricted || isDeployed}
                />
              </div>
            </Tooltip>
            {isRefDomainRestricted && (
              <div style={{ 
                color: '#666', 
                fontSize: '12px', 
                marginTop: '4px',
                fontStyle: 'italic'
              }}>
                This refcode domain is restricted and cannot be changed.
              </div>
            )}
          </>
        )}

        {mode === "dependency" && (
          <>
            <FAWDropdown
              label="Available Droplists:"
              value={dependencyDroplist}
              onChange={(opt)=> setDependencyDroplist(opt?.value || "")}
              options={[
                { label: "--Select--", value: "" },
                ...(availableDroplists || []).map(d => ({ 
                  label: d.label || d.text || String(d), 
                  value: d.value || d.id || String(d) 
                }))
              ]}
            />
            <FAWDropdown
              label="Ref Domains:"
              value={dependencyDomain}
              onChange={(opt)=> setDependencyDomain(opt?.value || "")}
              options={[
                { label: "--Select--", value: "" },
                ...(domains || [])
                  .map(d => ({
                    label: d.Name || d.Description || String(d),
                    value: d.Name || String(d)
                  }))
              ]}
            />
          </>
        )}

        {mode === "formField" && (
          <FAWDropdown
            label="Available Fields"
            value={formFieldId}
            onChange={(opt)=> setFormFieldId(opt?.value || "")}
            options={(availableFormFields || []).map(f => ({ label: f.label || f.text || String(f), value: f.value || f.id || String(f) }))}
          />
        )}
      </div>



          {mode === "staticList" && (
          <div>
            {/* DataGrid-like structure matching legacy ItemOptionEditor.ascx */}
            <div style={{ 
              border: "1px solid #ddd", 
              borderRadius: 4,
              width: "99%",
              marginBottom: "16px"
            }}>
              {/* Header row - matching DataGridHeader style */}
              <div style={{ 
                display: "grid", 
                gridTemplateColumns: "30% 70%", 
                gap: 0, 
                padding: "8px 12px", 
                backgroundColor: "#f5f5f5", 
                borderBottom: "1px solid #ddd",
                fontWeight: "bold",
                fontSize: "14px"
              }}>
                <div>Save Value</div>
                <div>Display Text</div>
              </div>
              
              {/* Data rows - matching DataGridItem/DataGridAlternatingItem styles */}
              <div>
                {inlineOptions.map((row, index) => {
                  const invalidSaveValue = !SAVE_VALUE_REGEX.test(row.optionValue || "");
                  const isAlternating = index % 2 === 1;
                  return (
                    <div key={row.id} style={{ 
                      display: "grid", 
                      gridTemplateColumns: "30% 70%", 
                      gap: 0, 
                      padding: "8px 12px", 
                      borderBottom: "1px solid #eee",
                      backgroundColor: isAlternating ? "#f9f9f9" : "#ffffff",
                      minHeight: "60px",
                      alignItems: "start"
                    }}>
                      {/* Save Value column */}
                      <div style={{ paddingRight: "8px" }}>
                        <FAWInput 
                          key={`save-${row.id}`}
                          value={row.optionValue} 
                          onChange={(e)=> updateRow(row.id, { optionValue: e.target.value })}
                          placeholder="Enter save value"
                          size="small"
                          maxLength={30}
                          fullWidth={true}
                          sx={{ width: '100%' }}
                        />
                        {invalidSaveValue && (
                          <div style={{ color: "#c00", fontSize: 12, marginTop: 4 }}>
                            Save Value cannot contain any spaces or special characters
                          </div>
                        )}
                      </div>
                      
                      {/* Display Text column */}
                      <div style={{ paddingRight: "8px" }}>
                        <FAWInput
                          key={`display-${row.id}`}
                          value={row.optionText} 
                          onChange={(e)=> updateRow(row.id, { optionText: e.target.value })}
                          placeholder="Enter display text"
                          size="small"
                          maxLength={1000}
                          fullWidth={true}
                          sx={{ width: '100%' }}
                        />
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>

            {/* Add 5 Rows Button - Mirroring legacy */}
            <div style={{ display: "flex", gap: 8, marginTop: 8 }}>
              <FAWButton 
                variant="outlined" 
                onClick={()=> { for (let i=0;i<5;i++) addRow(); }}
                style={{ marginBottom: "16px" }}
              >
                Add 5 Rows
              </FAWButton>
            </div>
          </div>
        )}
    </div>
  );
}


